import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-code", desc: "Building high-speed, futuristic websites that convert visitors into loyal customers.", color: "#0d6efd" },
    { id: 2, title: "UI/UX Design", icon: "fas fa-layer-group", desc: "Pixel-perfect designs focused on user psychology and modern digital aesthetics.", color: "#dc3545" },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", desc: "Powerful native and cross-platform apps with seamless and smooth user experiences.", color: "#198754" },
    { id: 4, title: "Assignment Support", icon: "fas fa-book-reader", desc: "Expert academic guidance to help you excel in your technical projects and finals.", color: "#ffc107" },
    { id: 5, title: "PPT Design", icon: "fas fa-file-powerpoint", desc: "High-impact visual storytelling that makes your presentations truly unforgettable.", color: "#0dcaf0" },
    { id: 6, title: "Report Writing", icon: "fas fa-file-signature", desc: "Professional, data-driven technical reports and structured business documentation.", color: "#6c757d" },
    { id: 7, title: "Digital Marketing", icon: "fas fa-bullhorn", desc: "Strategic growth campaigns to enhance your online presence and market reach.", color: "#343a40" },
    { id: 8, title: "Content Writing", icon: "fas fa-pen-nib", desc: "Engaging and SEO-optimized content that speaks your brand's unique voice.", color: "#0d6efd" },
    { id: 9, title: "SEO Optimization", icon: "fas fa-search-plus", desc: "Improve your search engine rankings and attract organic traffic with ease.", color: "#20c997" }
  ];

  return (
    <div className="premium-services-page py-5">
      <div className="container py-5">
        
        {/* Modern Centered Header */}
        <div className="text-center mb-5 pb-4">
          <h2 className="fw-bold display-5 mb-3 text-dark">Our Specialized Services</h2>
          <p className="text-muted fs-5 mx-auto" style={{ maxWidth: '600px' }}>
            We provide world-class digital solutions to help you grow and succeed in the modern era.
          </p>
          <div className="accent-bar mx-auto"></div>
        </div>

        <div className="row g-4">
          {serviceData.map((service) => (
            <div className="col-lg-4 col-md-6" key={service.id}>
              <div className="service-card-modern h-100 shadow-sm">
                {/* ID Number in corner */}
                <span className="card-number">0{service.id}</span>
                
                {/* Icon Circle */}
                <div className="icon-wrapper" style={{ '--icon-color': service.color }}>
                  <i className={service.icon}></i>
                </div>

                <div className="card-body-text mt-4">
                  <h4 className="fw-bold">{service.title}</h4>
                  <p className="text-muted small mb-4">{service.desc}</p>
                </div>

                <div className="card-footer-action">
                  <Link to="/register" className="btn-action-link" style={{ '--btn-color': service.color }}>
                    Start Now <i className="fas fa-arrow-right ms-2"></i>
                  </Link>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com');

        .premium-services-page {
          background-color: #fcfdfe;
          font-family: 'Outfit', sans-serif;
        }

        .accent-bar {
          width: 60px;
          height: 4px;
          background: #0d6efd;
          border-radius: 10px;
        }

        .service-card-modern {
          position: relative;
          background: #ffffff;
          border-radius: 24px;
          padding: 40px 30px;
          border: 1px solid #f1f1f1;
          transition: all 0.4s cubic-bezier(0.165, 0.84, 0.44, 1);
          overflow: hidden;
          display: flex;
          flex-direction: column;
        }

        .card-number {
          position: absolute;
          top: 20px;
          right: 25px;
          font-weight: 800;
          font-size: 1.2rem;
          color: #f0f0f0;
          transition: 0.3s;
        }

        .icon-wrapper {
          width: 65px;
          height: 65px;
          background: #fff;
          box-shadow: 0 10px 25px rgba(0,0,0,0.05);
          border-radius: 18px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 1.6rem;
          color: var(--icon-color);
          transition: 0.4s;
          border: 1px solid #f8f8f8;
        }

        .service-card-modern:hover {
          transform: translateY(-12px);
          box-shadow: 0 30px 60px rgba(0,0,0,0.08) !important;
          border-color: transparent;
        }

        .service-card-modern:hover .icon-wrapper {
          background-color: var(--icon-color);
          color: #fff;
          transform: rotate(-10deg) scale(1.1);
          box-shadow: 0 15px 30px rgba(0,0,0,0.1);
        }

        .service-card-modern:hover .card-number {
          color: #eef2ff;
          transform: scale(1.2);
        }

        .btn-action-link {
          text-decoration: none;
          font-weight: 700;
          font-size: 0.9rem;
          color: #2c3e50;
          display: inline-flex;
          align-items: center;
          transition: 0.3s;
        }

        .btn-action-link:hover {
          color: var(--btn-color);
          letter-spacing: 1px;
        }

        @media (max-width: 768px) {
          .display-5 { font-size: 2rem; }
        }
      `}</style>
    </div>
  );
}

export default Services;
